import{_ as n,o as s,c as i,f as e}from"./app-55c326ac.js";const o={},t=e('<h1 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h1><h2 id="ansible条款" tabindex="-1"><a class="header-anchor" href="#ansible条款" aria-hidden="true">#</a> Ansible条款</h2><ul><li><strong>控制器机器</strong>：安装了Ansible的机器，负责在您管理的服务器上运行配置</li><li><strong>清单</strong>：INI包含有关您正在管理的服务器的信息的文件</li><li><strong>Playbook</strong>：Ansible provisionings的入口点，其中自动化是通过使用YAML格式的任务定义的</li><li><strong>任务</strong>：定义要执行的单个过程的块，例如：安装包</li><li><strong>模块</strong>：模块通常抽象系统任务，如处理包或创建和更改文件。Ansible有许多内置模块，但您也可以创建自定义模块</li><li><strong>角色</strong>：用于组织剧本和其他文件的预定义方式，以便于共享和重用部分配置</li><li><strong>播放</strong>：从开始到结束执行的配置称为播放</li><li><strong>事实</strong>：包含有关系统信息的全局变量，如网络接口或操作系统</li><li><strong>处理程序</strong>：用于触发服务状态更改，如重新启动或停止服务</li></ul><p>Ansible供应是使用<code>YAML</code>简单的数据序列化语言编写的。</p>',4),r=[t];function l(a,c){return s(),i("div",null,r)}const g=n(o,[["render",l],["__file","简介.html.vue"]]);export{g as default};
